#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long sum = 0; int mn = 101; // Ai in [-100,100]
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            sum += x;
            if(x < mn) mn = x;
        }
        printf("%lld\n", sum - mn);
    }
    return 0;
}

